// ==================== INITIALIZATION ====================

let wasmInitialized = false;
let wasmModule = null;

/**
 * Initialize the WASM module
 * Must be called before using any Kenny AGI functionality
 * @returns {Promise<void>}
 */
export async function initializeWasm() {
    if (wasmInitialized) {
        return;
    }

    try {
        wasmModule = await init();
        wasmInitialized = true;
        console.log('[Kenny AGI WASM] Module initialized successfully');
    } catch (error) {
        console.error('[Kenny AGI WASM] Initialization failed:', error);
        throw new Error(`WASM initialization failed: ${error.message}`);
    }
}

/**
 * Check if WASM module is initialized
 * @returns {boolean}
 */
export function isWasmInitialized() {
    return wasmInitialized;
}

// ==================== ERROR HANDLING ====================

/**
 * Kenny WASM Error class
 */
export class KennyWasmError extends Error {
    constructor(message, code = null, originalError = null) {
        super(message);
        this.name = 'KennyWasmError';
        this.code = code;
        this.originalError = originalError;
    }
}

/**
 * Wrap WASM calls with error handling
 * @param {Function} wasmCall - The WASM function to call
 * @param {string} operation - Description of the operation
 * @returns {Promise<any>}
 */
async function safeWasmCall(wasmCall, operation) {
    if (!wasmInitialized) {
        throw new KennyWasmError(
            'WASM module not initialized. Call initializeWasm() first.',
            'WASM_NOT_INITIALIZED'
        );
    }

    try {
        return await wasmCall();
    } catch (error) {
        console.error(`[Kenny AGI WASM] ${operation} failed:`, error);
        throw new KennyWasmError(
            `${operation} failed: ${error.message}`,
            'WASM_OPERATION_FAILED',
            error
        );
    }
}

