    // ==================== WEBSOCKET OPERATIONS ====================

    /**
     * Connect to WebSocket for real-time events
     * @returns {Promise<void>}
     */
    async connectWebSocket() {
        this._ensureInitialized();
        await safeWasmCall(
            () => this._wasmInstance.connect_websocket(),
            'Connect WebSocket'
        );
        this._connectionState.websocket = true;
        console.log('[Kenny AGI WASM] WebSocket connected');
    }

    /**
     * Register event listener
     * @param {string} eventType - Type of event to listen for
     * @param {Function} callback - Callback function
     */
    addEventListener(eventType, callback) {
        if (!this._eventListeners.has(eventType)) {
            this._eventListeners.set(eventType, []);
        }
        this._eventListeners.get(eventType).push(callback);

        // Register with WASM instance if connected
        if (this._wasmInstance && this._connectionState.websocket) {
            this._wasmInstance.register_event_listener(eventType, (event) => {
                this._handleWebSocketEvent(eventType, event);
            });
        }
    }

    /**
     * Remove event listener
     * @param {string} eventType - Type of event
     * @param {Function} callback - Callback to remove
     */
    removeEventListener(eventType, callback) {
        if (this._eventListeners.has(eventType)) {
            const listeners = this._eventListeners.get(eventType);
            const index = listeners.indexOf(callback);
            if (index > -1) {
                listeners.splice(index, 1);
            }
        }
    }

    /**
     * Handle WebSocket events
     * @param {string} eventType - Event type
     * @param {Object} eventData - Event data
     * @private
     */
    _handleWebSocketEvent(eventType, eventData) {
        if (this._eventListeners.has(eventType)) {
            const listeners = this._eventListeners.get(eventType);
            listeners.forEach(callback => {
                try {
                    callback(eventData);
                } catch (error) {
                    console.error(`[Kenny AGI WASM] Event listener error:`, error);
                }
            });
        }
    }

    /**
     * Send WebSocket message
     * @param {Object} message - Message to send
     * @returns {Promise<void>}
     */
    async sendWebSocketMessage(message) {
        this._ensureInitialized();
        
        if (!this._connectionState.websocket) {
            throw new KennyWasmError(
                'WebSocket not connected. Call connectWebSocket() first.',
                'WEBSOCKET_NOT_CONNECTED'
            );
        }

        return await safeWasmCall(
            () => this._wasmInstance.send_websocket_message(JSON.stringify(message)),
            'Send WebSocket message'
        );
    }

    /**
     * Close WebSocket connection
     * @returns {Promise<void>}
     */
    async closeWebSocket() {
        if (this._wasmInstance && this._connectionState.websocket) {
            await safeWasmCall(
                () => this._wasmInstance.close_websocket(),
                'Close WebSocket'
            );
            this._connectionState.websocket = false;
        }
    }

